// ===== STEP 1: SELEKSI ELEMEN DOM =====
// Hubungkan variabel JS ke elemen HTML via ID
// Letakkan ini di bagian ATAS file app.js

const articleForm   = document.getElementById('articleForm');
const inputTitle    = document.getElementById('inputTitle');
const inputContent  = document.getElementById('inputContent');
const btnSave       = document.getElementById('btnSave');
const tableBody     = document.getElementById('tableBody');
const modalOverlay  = document.getElementById('modalOverlay');
const toastNotif    = document.getElementById('toastNotif');

// Verifikasi: semua harus menampilkan elemen, bukan null
console.log('Form    :', articleForm);
console.log('Input   :', inputTitle);
console.log('Table   :', tableBody);
// Jika ada yang null = ID di HTML tidak cocok dengan yang di atas!

// ===== STEP 2: EVENT LISTENERS =====
// Daftarkan fungsi yang akan dipanggil saat event terjadi

articleForm.addEventListener('submit', function(event) {
  event.preventDefault(); // WAJIB — cegah reload halaman!
  console.log('Form di-submit!');
  console.log('Judul :', inputTitle.value);
  console.log('Konten:', inputContent.value);
});

// ===== MEMBACA DATA DARI ELEMEN =====
const judul   = inputTitle.value;    // Ambil teks yang diketik
const konten  = inputContent.value;  // Ambil isi textarea

// ===== MENULIS DATA KE ELEMEN =====
tableBody.innerHTML = '<tr><td>Test</td></tr>'; // Ganti seluruh isi
document.getElementById('jumlahData').textContent = '5 artikel'; // Ganti teks

// ===== MANIPULASI STYLE via CLASS =====
modalOverlay.classList.add('active');     // Tampilkan modal
modalOverlay.classList.remove('active'); // Sembunyikan modal
modalOverlay.classList.toggle('active'); // Toggle buka/tutup

// ===== PRAKTIK: Kontrol Modal via Event =====
btnSave.addEventListener('click', function() {
  // Ambil nilai input
  const title   = inputTitle.value.trim();
  const content = inputContent.value.trim();

  // Validasi sederhana
  if (!title || !content) {
    alert('Judul dan konten wajib diisi!'); // Sementara pakai alert
    return; // Hentikan eksekusi
  }

  // Tampilkan hasil di console (belum ke tabel)
  console.log({ title, content });
});
